'use client'

import { useState } from 'react'
import { DreTable } from '@/app/components/DreTable'
import { FilterSidebar } from '@/app/components/FilterSidebar'
import { YearSelector } from '@/app/components/YearSelector'
import { VersionSelector } from '@/app/components/VersionSelector'
import { DreRow } from '@/types/dre'

import { updateTenantDreTitle } from '@/app/actions/settings'

interface DreViewProps {
    initialData: DreRow[]
    tenantId: string
    dreTitle: string
    currentYear: number

    // New Props for Versions and Years
    versions: any[]
    currentVersionId: string
    minYear: number
    maxYear: number

    companies: any[]
    costCenters: any[]
    clients: any[]
    filters: {
        companyId?: string
        costCenterId?: string
        clientId?: string
    }
}

export function DreView({
    initialData,
    tenantId,
    dreTitle,
    currentYear,
    versions,
    currentVersionId,
    minYear,
    maxYear,
    companies,
    costCenters,
    clients,
    filters
}: DreViewProps) {
    const [isFullScreen, setIsFullScreen] = useState(false)
    const [isFiltersVisible, setIsFiltersVisible] = useState(true)

    // Title Editing State
    const [title, setTitle] = useState(dreTitle)
    const [isEditingTitle, setIsEditingTitle] = useState(false)
    const [tempTitle, setTempTitle] = useState(dreTitle)

    async function handleSaveTitle() {
        if (!tempTitle.trim()) return
        try {
            await updateTenantDreTitle(tempTitle)
            setTitle(tempTitle)
            setIsEditingTitle(false)
        } catch (e) {
            alert('Falha ao atualizar título')
            console.error(e)
        }
    }

    // Layout configuration based on FullScreen state
    const containerClasses = isFullScreen
        ? "fixed inset-0 z-50 bg-[var(--bg-main)] p-4 flex flex-col h-screen w-screen"
        : "space-y-6 flex flex-col h-[calc(100vh-100px)] relative"

    const toggleFullScreen = () => setIsFullScreen(!isFullScreen)

    return (
        <div className={containerClasses}>
            {/* Header Area */}
            <div className="flex justify-between items-center shrink-0 mb-4">
                <div className="flex items-center gap-4">
                    {/* Title Section */}
                    {isEditingTitle ? (
                        <div className="flex items-center gap-2">
                            <input
                                value={tempTitle}
                                onChange={e => setTempTitle(e.target.value)}
                                className="input-outline h-9 text-xl font-bold w-full min-w-[300px]"
                                autoFocus
                                onKeyDown={e => {
                                    if (e.key === 'Enter') handleSaveTitle()
                                    if (e.key === 'Escape') {
                                        setTempTitle(title)
                                        setIsEditingTitle(false)
                                    }
                                }}
                            />
                            <button onClick={handleSaveTitle} className="btn-icon text-[var(--success)] hover:bg-[var(--bg-surface-hover)]" title="Salvar">
                                <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><polyline points="20 6 9 17 4 12"></polyline></svg>
                            </button>
                            <button onClick={() => {
                                setTempTitle(title)
                                setIsEditingTitle(false)
                            }} className="btn-icon text-[var(--error)] hover:bg-[var(--bg-surface-hover)]" title="Cancelar">
                                <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><line x1="18" y1="6" x2="6" y2="18"></line><line x1="6" y1="6" x2="18" y2="18"></line></svg>
                            </button>
                        </div>
                    ) : (
                        <div className="flex items-center gap-2 group">
                            <h2 className="text-2xl font-bold">{title}</h2>
                            <button
                                onClick={() => {
                                    setTempTitle(title)
                                    setIsEditingTitle(true)
                                }}
                                className="opacity-0 group-hover:opacity-100 transition-opacity p-1.5 hover:bg-[var(--bg-surface-hover)] rounded-md text-[var(--text-muted)] hover:text-[var(--accent-primary)]"
                                title="Editar Título"
                            >
                                <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M12 20h9"></path><path d="M16.5 3.5a2.121 2.121 0 0 1 3 3L7 19l-4 1 1-4L16.5 3.5z"></path></svg>
                            </button>
                        </div>
                    )}

                    {/* Full Screen Button */}
                    <button
                        onClick={toggleFullScreen}
                        className="btn btn-ghost text-xs border border-[var(--border-subtle)] flex items-center gap-2"
                        title={isFullScreen ? "Sair da Tela Cheia" : "Expandir Tela"}
                    >
                        {isFullScreen ? (
                            <>
                                <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M8 3v3a2 2 0 0 1-2 2H3" /><path d="M21 8h-3a2 2 0 0 1-2-2V3" /><path d="M3 16h3a2 2 0 0 1 2 2v3" /><path d="M16 21v-3a2 2 0 0 1 2-2h3" /></svg>
                                <span>Reduzir</span>
                            </>
                        ) : (
                            <>
                                <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M15 3h6v6" /><path d="M9 21H3v-6" /><path d="M21 3l-7 7" /><path d="M3 21l7-7" /></svg>
                                <span>Tela Cheia</span>
                            </>
                        )}
                    </button>

                    {isFullScreen && (
                        <button
                            onClick={() => setIsFiltersVisible(!isFiltersVisible)}
                            className={`btn btn-ghost text-xs border border-[var(--border-subtle)] ${!isFiltersVisible ? 'text-[var(--text-muted)]' : 'text-[var(--accent-primary)]'}`}
                        >
                            {isFiltersVisible ? 'Ocultar Filtros' : 'Mostrar Filtros'}
                        </button>
                    )}
                </div>

                {/* Right Side Controls */}
                <div className="flex items-center gap-4">
                    <VersionSelector versions={versions} currentVersionId={currentVersionId} />
                    <YearSelector currentYear={currentYear} minYear={minYear} maxYear={maxYear} />
                </div>
            </div>

            <div className="flex gap-6 flex-1 min-h-0 overflow-hidden relative">
                {/* Filters */}
                {isFiltersVisible && (
                    <div className="shrink-0 transition-all duration-300">
                        <FilterSidebar
                            companies={companies}
                            costCenters={costCenters}
                            clients={clients}
                        />
                    </div>
                )}

                {/* Main Content */}
                <div className="flex-1 flex flex-col min-w-0 bg-[var(--bg-surface)] rounded-xl border border-[var(--border-subtle)] overflow-hidden shadow-2xl">
                    <DreTable
                        initialData={initialData}
                        tenantId={tenantId}
                        year={currentYear}
                        availableCompanies={companies}
                        filters={filters}
                    />
                </div>
            </div>
        </div>
    )
}
