'use client'

import { useRouter, useSearchParams, usePathname } from 'next/navigation'

interface FilterOption {
    id: string
    name: string
}

interface FilterSidebarProps {
    companies: FilterOption[]
    costCenters: FilterOption[]
    clients: FilterOption[]
}

export function FilterSidebar({ companies, costCenters, clients }: FilterSidebarProps) {
    const router = useRouter()
    const pathname = usePathname()
    const searchParams = useSearchParams()

    const updateFilter = (key: string, value: string) => {
        const params = new URLSearchParams(searchParams)
        if (value) {
            params.set(key, value)
        } else {
            params.delete(key)
        }
        router.push(`${pathname}?${params.toString()}`)
    }

    return (
        <div className="card w-[250px] flex-shrink-0 h-fit space-y-6">
            <div>
                <h3 className="font-bold mb-3 text-sm uppercase text-[var(--text-secondary)]">Filtros</h3>

                <div className="space-y-4">
                    <div>
                        <label className="block text-sm font-medium mb-1">Empresa</label>
                        <select
                            className="w-full p-2 rounded border border-[var(--border-subtle)] bg-[var(--bg-primary)] text-sm"
                            value={searchParams.get('companyId') || ''}
                            onChange={(e) => updateFilter('companyId', e.target.value)}
                        >
                            <option value="">Todas</option>
                            {companies.map(c => (
                                <option key={c.id} value={c.id}>{c.name}</option>
                            ))}
                        </select>
                    </div>

                    <div>
                        <label className="block text-sm font-medium mb-1">Centro de Custo</label>
                        <select
                            className="w-full p-2 rounded border border-[var(--border-subtle)] bg-[var(--bg-primary)] text-sm"
                            value={searchParams.get('costCenterId') || ''}
                            onChange={(e) => updateFilter('costCenterId', e.target.value)}
                        >
                            <option value="">Todos</option>
                            {costCenters.map(c => (
                                <option key={c.id} value={c.id}>{c.name}</option>
                            ))}
                        </select>
                    </div>

                    <div>
                        <label className="block text-sm font-medium mb-1">Cliente</label>
                        <select
                            className="w-full p-2 rounded border border-[var(--border-subtle)] bg-[var(--bg-primary)] text-sm"
                            value={searchParams.get('clientId') || ''}
                            onChange={(e) => updateFilter('clientId', e.target.value)}
                        >
                            <option value="">Todos</option>
                            {clients.map(c => (
                                <option key={c.id} value={c.id}>{c.name}</option>
                            ))}
                        </select>
                    </div>
                </div>
            </div>
        </div>
    )
}
